#pragma GCC target("avx2")
#pragma GCC optimize("Ofast")
#pragma GCC optimize("unroll-loops")

#include <bits/stdc++.h>
using namespace std;

#define b_k 100
#define n 9

// 上下左右


inline int move_x(int move_n) {
    if (move_n == 0) return 1;
    if (move_n == 1) return -1;
    return 0;
}


inline int move_y(int move_n) {
    if (move_n == 2) return 1;
    if (move_n == 3) return -1;
    return 0;
}


// 評価関数: 自分のマスのスコア - 相手のマスのスコア


class Game {
public:
    bool is_black;
    vector<vector<bool>> is_apple;
    vector<vector<vector<bool>>> can_move;
    int my_wall_cnt;
    int enemy_wall_cnt;
    int my_x;
    int my_y;
    int enemy_x;
    int enemy_y;

    Game (vector<vector<bool>> board, bool is_black) {
        is_black = is_black;
        is_apple = board;
        can_move = vector<vector<vector<bool>>>(n, vector<vector<bool>>(n, vector<bool>(4, true)));
        for (int i = 0; i < n; i++) {
            can_move[0][i][0] = false;
            can_move[n - 1][i][1] = false;
            can_move[i][0][2] = false;
            can_move[i][n - 1][3] = false;
        }

        my_wall_cnt = 10;
        enemy_wall_cnt = 10;

        if (is_black) {
            my_x = 8;
            my_y = 4;
            enemy_x = 0;
            enemy_y = 4;
        } else {
            my_x = 0;
            my_y = 4;
            enemy_x = 8;
            enemy_y = 4;
        }
    }

    vector<vector<int>> bfs(int x, int y) {
        vector<vector<int>> dist = vector<vector<int>>(n, vector<int>(n, -1));
        dist[x][y] = 0;
        queue<pair<int, int>> q;
        q.push({x, y});
        while (!q.empty()) {
            int i = q.front().first;
            int j = q.front().second;
            q.pop();
            for (int m_n = 0; m_n < 4; m_n++) {
                if (!can_move[i][j][m_n]) continue;
                int nx = i + move_x(m_n);
                int ny = j + move_y(m_n);
                if (dist[nx][ny] == -1) {
                    dist[nx][ny] = dist[i][j] + 1;
                    q.push({nx, ny});
                }
            }
        }
    }

    bool is_joined() {
        vector<vector<int>> dist = bfs(0, 0);
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (dist[i][j] == -1) {
                    return false;
                }
            }
        }
        return true;
    }

    int get_score(int x, int y) {
        vector<vector<int>> dist = bfs(x, y);
        int ans = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < n; j++) {
                if (is_apple[i][j]) {
                    ans += dist[i][j];
                }
            }
        }
        return ans;
    }

    int get_board_score(int x, int y, int ex, int ey) {
        return get_score(x, y) - get_score(ex, y);
    }

    int choice_move() {
        int ans = -1;
        int best_score = get_score(my_x, my_y);
        for (int m_n = 0; m_n < 4; m_n++) {
            if (can_move[my_x][my_y][m_n]) {
                int nx = my_x + move_x(m_n);
                int ny = my_y + move_y(m_n);
                int score = get_score(nx, ny);
                if (score > best_score) {
                    best_score = score;
                    ans = m_n;
                }
            }
        }

        return ans;
    }

    int choice_wall {

    };

    pair<int, pair<int, int>> choice_action() {
        int ans = -1;
        int wall_no = -1;
        int wall_x = -1;
        int wall_y = -1;
        int best_score = 0;
        for (int m_n = 0; m_n < 4; m_n++) {
            if (can_move[my_x][my_y][m_n]) {
                int nx = my_x + move_x(m_n);
                int ny = my_y + move_y(m_n);
                int score = get_board_score(nx, ny, enemy_x, enemy_y);
                if (score > best_score) {
                    best_score = score;
                    ans = m_n;
                }
            }
        }

        for (int i = 0; i < n - 1; i++) {
            for (int j = 0; j < n - 1; j++) {
                if (my_wall_cnt == 0) break;
                if (!can_move[i][j][3]) continue;
                if (!can_move[i+1][j][3]) continue;
                can_move[i][j][3] = false;
                can_move[i+1][j][3] = false;
                if (!is_joined()) {
                    can_move[i][j][3] = true;
                    can_move[i+1][j][3] = true;
                    continue;
                }

                my_wall_cnt--;

                int score = get_board_score(my_x, my_y, enemy_x, enemy_y);
                if (score > best_score) {
                    best_score = score;
                    ans = 4;
                    wall_no = 2;
                    wall_x = i;
                    wall_y = j;
                }

                can_move[i][j][3] = true;
                can_move[i+1][j][3] = true;
                my_wall_cnt++;
            }
        }

        for (int i = 0; i < n - 1; i++) {
            for (int j = 0; j < n - 1; j++) {
                if (my_wall_cnt == 0) break;
                if (!can_move[i][j][1]) continue;
                if (!can_move[i][j+1][1]) continue;
                can_move[i][j][1] = false;
                can_move[i][j+1][1] = false;
                if (!is_joined()) {
                    can_move[i][j][1] = true;
                    can_move[i][j+1][1] = true;
                    continue;
                }

                my_wall_cnt--;

                int score = get_board_score(my_x, my_y, enemy_x, enemy_y);
                if (score > best_score) {
                    best_score = score;
                    ans = 4;
                    wall_no = 1;
                    wall_x = i;
                    wall_y = j;
                }

                can_move[i][j][1] = true;
                can_move[i][j+1][1] = true;
                my_wall_cnt++;
            }
        }

        if (wall_x == -1) {
            return {0, {ans, -1}};
        } else {
            return {wall_no, {wall_x, wall_y}};
        }
    }

    void action(bool is_mine, pair<int, pair<int, int>> ac) {
        if (is_mine) {
            if (ac.first == 0) {
                my_x += move_x(ac.second.first);
                my_y += move_y(ac.second.first);
            } else {
                my_wall_cnt--;
                if (ac.first == 1) {
                    can_move[ac.second.first][ac.second.second][3] = false;
                    can_move[ac.second.first][ac.second.second+1][3] = false;
                } else {
                    can_move[ac.second.first][ac.second.second][1] = false;
                    can_move[ac.second.first+1][ac.second.second][1] = false;
                }
            }
        } else {
            if (ac.first == 0) {
                enemy_x += move_x(ac.second.first);
                enemy_y += move_y(ac.second.first);
            } else {
                enemy_wall_cnt--;
                if (ac.first == 1) {
                    can_move[ac.second.first][ac.second.second][3] = false;
                    can_move[ac.second.first][ac.second.second+1][3] = false;
                } else {
                    can_move[ac.second.first][ac.second.second][1] = false;
                    can_move[ac.second.first+1][ac.second.second][1] = false;
                }
            }
        }
    }
};

int main() {
    string my_hand;
    cin >> my_hand;
    vector<vector<bool>> board(n, vector<bool>(n, false));
    for (int i = 0; i < n; i++) {
        string line;
        cin >> line;
        for (int j = 0; j < n; j++) {
            if (line[j] == '#') board[i][j] = true;
        }
    }

    Game game = Game(board, my_hand == "First");
    bool is_my_turn = my_hand == "First";
    for (int _ = 0; _ < 150; _++) {
        if (is_my_turn) {
            pair<int, pair<int, int>> ac = game.choice_action();
            game.action(true, ac);
            if (ac.first == 1) {
                int no = ac.second.first;
                if (no >= 1) {
                    no++;
                    if (no == 4) {
                        no = 1;
                    }
                }
                cout << 0 << " " << no << endl;
            } else {
                cout << ac.first << " " << ac.second.first << " " << ac.second.second << endl;
            }
        } else {
            int ac_no;
            cin >> ac_no;
            if (ac_no == 0) {
                int no;
                cin >> no;
                no--;
                if (no == 0) {
                    no = 3;
                }
                if (no == -1) {
                    no = 0;
                }
                game.action(false, {0, {no, 0}});
            } else {
                int ac_x, ac_y;
                cin >> ac_x >> ac_y;
                game.action(false, {ac_no, {ac_x, ac_y}});
            }
        }
    }
}
